    // 补：i=1..y-1 的直接加 floor(n/i)
    for (i64 i = 1; i < y; ++i) area_sum += (n / i);

    // S(n) = 2*sum_{i=1..floor(sqrt n)} floor(n/i) - floor(sqrt n)^2
    // 这里 area_sum 就是 sum_{i=1..floor(sqrt n)} floor(n/i)
    i128 ans = area_sum * 2 - (i128)B * (i128)B;
    return ans;
}

